1	/**
2	 * Calendar read (background only). Two jobs:
3	 *  1) resolve the canonical event for a given eid (events.get) — authoritative
4	 *     iCalUID + attendees for the side panel.
5	 *  2) list changes via a sync token (events.list) — the durable "what changed"
6	 *     API that drives post-save refresh + the visitor-event nudge/badge.
7	 * Calendar.events.readonly only.
8	 */
9	import { MAGIC_ADDRESS } from './config';
10	import type { ActiveEvent } from './types';
11	
12	/** `eid` is URL-safe base64 of "<eventId> <calendarId>" (calendarId optional). */
13	export function decodeEid(eid: string): { eventId: string; calendarId: string } | null {
14	  try {
15	    let b64 = eid.replace(/-/g, '+').replace(/_/g, '/');
16	    b64 += '='.repeat((4 - (b64.length % 4)) % 4);
17	    const decoded = atob(b64);
18	    const [eventId, calendarId] = decoded.split(' ');
19	    if (!eventId) return null;
20	    return { eventId, calendarId: calendarId || 'primary' };
21	  } catch {
22	    return null;
23	  }
24	}
25	
26	/** Inverse of decodeEid — build an eid the side panel can resolve. */
27	export function encodeEid(eventId: string, calendarId = 'primary'): string {
28	  const b64 = btoa(`${eventId} ${calendarId}`);
29	  return b64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
30	}
31	
32	export interface GCalEvent {
33	  id?: string;
34	  iCalUID?: string;
35	  status?: string;
36	  summary?: string;
37	  location?: string;
38	  description?: string;
39	  /** Present on instances of a recurring series (with singleEvents=true): the id
40	   *  of the parent series. Lets us treat a series as one nudge unit. */
