1	/**
2	 * Calendar sync (background only). The durable, official "what changed" engine:
3	 * runs on a chrome.alarm, lists changes via a sync token, and maintains the set
4	 * of upcoming visitor (magic-address) events in storage.local. Drives:
5	 *  - post-save refresh of the open event (changedIds),
6	 *  - the visitor-event notification + toolbar badge (newMarked / count),
7	 *  - the side panel's "open from list" picker (listMarked).
8	 * No DOM. Reflects SAVED state only (pre-save edits are add-on-only — see
9	 * Planning-docs/2026-06-19_calendar_addon_vs_extension_capabilities.md).
10	 */
11	import { encodeEid, isMarked, listEvents } from './calendar';
12	import type { VisitorEventSummary } from './types';
13	
14	const SYNC_TOKEN_KEY = 'auxilio.syncToken';
15	const MARKED_KEY = 'auxilio.markedEvents';
16	/** Events the user has already issued passes for from this extension — keyed by
17	 *  eventId, value = when handled. A durable overlay over the marked set so a
18	 *  finished event stops badging/notifying/nudging instead of nagging until it
19	 *  ages out. Local-only signal: passes sent via the add-on or another device
20	 *  won't appear here (full cross-channel truth needs an engine status endpoint —
21	 *  deferred). Pruned by HANDLED_TTL_MS. */
22	const HANDLED_KEY = 'auxilio.handledEvents';
23	const PAST_GRACE_MS = 60 * 60_000; // keep events until 1h after they end
24	const HANDLED_TTL_MS = 30 * 24 * 60 * 60_000; // forget "handled" after 30 days
25	
26	type MarkedMap = Record<string, VisitorEventSummary>;
27	type HandledMap = Record<string, number>;
28	
29	async function readMarked(): Promise<MarkedMap> {
30	  const r = await chrome.storage.local.get(MARKED_KEY);
31	  return (r[MARKED_KEY] as MarkedMap) ?? {};
32	}
33	
34	async function readHandled(): Promise<HandledMap> {
35	  const r = await chrome.storage.local.get(HANDLED_KEY);
36	  return (r[HANDLED_KEY] as HandledMap) ?? {};
37	}
38	
39	/** Record that passes were issued for this event — drops it from every nudge
40	 *  surface (badge, banner, notification, picker) until it ages out. */
41	export async function markHandled(eventId: string): Promise<void> {
42	  if (!eventId) return;
43	  const handled = await readHandled();
44	  handled[eventId] = Date.now();
45	  await chrome.storage.local.set({ [HANDLED_KEY]: handled });
46	}
47	
48	export interface SyncResult {
49	  changedIds: Set<string>;
50	  newMarked: VisitorEventSummary[];
51	  /** Events seen this cycle that are no longer pending visitor events (deleted/
52	   *  cancelled). Lets the in-page nudge purge stale optimistic guesses. */
53	  cancelledIds: string[];
54	  markedCount: number;
55	}
56	
57	/** Pull changes since the last sync; update the marked set; report deltas. */
58	export async function runSync(accessToken: string): Promise<SyncResult> {
59	  const store = await chrome.storage.local.get([SYNC_TOKEN_KEY, MARKED_KEY, HANDLED_KEY]);
60	  let syncToken = store[SYNC_TOKEN_KEY] as string | undefined;
61	  let marked = (store[MARKED_KEY] as MarkedMap) ?? {};
62	  const handled = (store[HANDLED_KEY] as HandledMap) ?? {};
63	
64	  let resp = await listEvents(accessToken, { syncToken });
65	  if (resp.expired) {
66	    // Token stale → full resync from scratch.
67	    syncToken = undefined;
68	    marked = {};
69	    resp = await listEvents(accessToken, {});
70	  }
71	
72	  const changedIds = new Set<string>();
73	  const newMarked: VisitorEventSummary[] = [];
74	  const cancelledIds: string[] = [];
75	
76	  // Series we already track (any existing marked instance) — so a newly discovered
77	  // later occurrence of a known recurring event doesn't fire a fresh notification.
78	  const knownSeries = new Set(
79	    Object.values(marked).map((m) => m.seriesId ?? m.eventId),
80	  );
81	  // Series notified within THIS cycle — collapses an initial sync that discovers
82	  // dozens of weekly instances at once down to a single notification.
83	  const notifiedSeries = new Set<string>();
84	
85	  for (const ev of resp.items) {
86	    if (!ev.id) continue;
87	    changedIds.add(ev.id);
88	    const cancelled = ev.status === 'cancelled';
89	    if (isMarked(ev) && !cancelled) {
90	      const seriesId = ev.recurringEventId || ev.id;
91	      const summary: VisitorEventSummary = {
92	        eid: encodeEid(ev.id, 'primary'),
93	        eventId: ev.id,
94	        iCalUid: ev.iCalUID ?? '',
95	        title: ev.summary || '(no title)',
96	        start: ev.start?.dateTime ?? ev.start?.date,
97	        seriesId,
98	      };
99	      // Notify only for a genuinely new, not-yet-handled occurrence of a series we
100	      // aren't already tracking — one alert per recurring series, not per instance.
101	      const newInstance = !marked[ev.id] && !handled[ev.id];
102	      if (newInstance && !knownSeries.has(seriesId) && !notifiedSeries.has(seriesId)) {
103	        newMarked.push(summary);
104	        notifiedSeries.add(seriesId);
105	      }
106	      marked[ev.id] = summary;
107	    } else {
108	      // Cancelled (deleted) or no longer a visitor event → not pending. Report
109	      // it so any optimistic in-page nudge for it gets purged, and forget any
110	      // "handled" record so the id can't linger.
111	      if (cancelled || marked[ev.id]) cancelledIds.push(ev.id);
112	      delete marked[ev.id];
113	      delete handled[ev.id];
114	    }
115	  }
116	
117	  // Prune events that are well past.
118	  const cutoff = Date.now() - PAST_GRACE_MS;
119	  for (const id of Object.keys(marked)) {
120	    const s = marked[id].start;
121	    if (s && Date.parse(s) < cutoff) delete marked[id];
122	  }
123	
124	  // Prune stale "handled" records so the overlay can't grow without bound.
125	  const handledCutoff = Date.now() - HANDLED_TTL_MS;
126	  for (const id of Object.keys(handled)) {
127	    if (handled[id] < handledCutoff) delete handled[id];
128	  }
129	
130	  await chrome.storage.local.set({
131	    [SYNC_TOKEN_KEY]: resp.nextSyncToken ?? syncToken,
132	    [MARKED_KEY]: marked,
133	    [HANDLED_KEY]: handled,
134	  });
135	
136	  // markedCount drives the toolbar badge — count distinct pending series (a
137	  // recurring event counts once, not once per occurrence).
138	  const pendingSeries = new Set<string>();
139	  for (const id of Object.keys(marked)) {
140	    if (!handled[id]) pendingSeries.add(marked[id].seriesId ?? id);
141	  }
142	  return { changedIds, newMarked, cancelledIds, markedCount: pendingSeries.size };
143	}
144	
145	/** Upcoming visitor events still needing passes, soonest first — for the panel's
146	 *  picker and the in-page nudge. Handled events are filtered out, and a recurring
147	 *  series collapses to its soonest pending occurrence (one row, not one per week). */
148	export async function listMarked(): Promise<VisitorEventSummary[]> {
149	  const [marked, handled] = await Promise.all([readMarked(), readHandled()]);
150	  const bySeries = new Map<string, VisitorEventSummary>();
151	  for (const m of Object.values(marked)) {
152	    if (handled[m.eventId]) continue;
153	    const key = m.seriesId ?? m.eventId;
154	    const existing = bySeries.get(key);
155	    if (!existing || (m.start ?? '~').localeCompare(existing.start ?? '~') < 0) {
156	      bySeries.set(key, m);
157	    }
158	  }
159	  return [...bySeries.values()].sort((a, b) =>
160	    (a.start ?? '').localeCompare(b.start ?? ''),
161	  );
162	}
163	
164	/** Is this event id currently a known visitor event? */
165	export async function isEventMarked(eventId: string): Promise<boolean> {
166	  const marked = await readMarked();
167	  return !!marked[eventId];
168	}
