322	        if (!editEid && msg.eventId) {
323	          const email = t.email ?? (await authStatus()).email ?? 'primary';
324	          editEid = encodeEid(msg.eventId, email);
325	        }
326	        // The web editor needs the *real* calendar id in the eid — for the
327	        // primary calendar that's the user's email, not the literal "primary"
328	        // (which the Calendar API accepts but the /eventedit URL can't resolve).
329	        // Sync/nudge eids are encoded with "primary", so rewrite them here.
330	        if (editEid) {
331	          const dec = decodeEid(editEid);
332	          if (dec && (dec.calendarId === 'primary' || !dec.calendarId)) {
333	            const email = t.email ?? (await authStatus()).email;
334	            if (email) editEid = encodeEid(dec.eventId, email);
335	          }
336	        }
337	        // Google's eventedit eid is base64 with padding stripped — normalize the
338	        // raw data-eventid (which may carry `=` padding) to match.
339	        if (editEid) editEid = editEid.replace(/=+$/, '');
340	        if (!editEid) return { navigated: false };
341	        const tabs = await chrome.tabs.query({ url: 'https://calendar.google.com/*' });
342	        const tab = tabs.find((x) => x.active) ?? tabs[0];
343	        if (tab?.id == null || !tab.url) return { navigated: false };
344	        // Build the edit-screen URL from the /u/<n>/ account segment.
345	        const u = tab.url.match(/\/calendar\/(u\/\d+\/)?/);
346	        const userSeg = u?.[1] ?? '';
347	        const url = `https://calendar.google.com/calendar/${userSeg}r/eventedit/${editEid}`;
348	        console.log('[auxilio] navigate →', { from: tab.url, to: url, editEid });
349	        await chrome.tabs.update(tab.id, { url, active: true });
350	        return { navigated: true };
351	      });
352	
353	    default:
354	      return { ok: false, error: 'Unknown request' };
355	  }
356	}
